scwin.RetriveBranch = function () {
  if (acb_STYPE.getValue() == 0) {
    //조회조건이 하나도 없다			
    dma_search.set("stype", acb_STYPE.getValue());
    dma_search.set("stext", "");
    ds_Branch.setJSON([]);
    $c.sbm.execute($p, sbm_reterieve);
  } else {
    if ($c.str.trim($p, ed_STEXT.getValue()) != "") {
      dma_search.set("stype", acb_STYPE.getValue());
      dma_search.set("stext", ed_STEXT.getValue());
    } else {
      $c.win.alert($p, "조회조건이 입력되지 않았습니다.");
      return;
    }
    ds_Branch.setJSON([]);
    $c.sbm.execute($p, sbm_reterieve);
  }
};

